const d = $input.item.json || {};
const wf = d.workflow || {};
const ex = d.execution || {};
const err = ex.error || {};
const wfName = wf.name || '(desconocido)';
const node = ex.lastNodeExecuted || '(desconocido)';
const msg = err.message || err.description || '(sin mensaje)';
const stack = String(err.stack || '').split('\n').slice(0, 6).join('\n');
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const subject = '[n8n] Fallo: ' + wfName + ' -> ' + node;
const html = '<div style="font-family:sans-serif;color:#0f172a">' +
  '<h2 style="color:#dc2626">Un workflow de n8n ha fallado</h2>' +
  '<p><b>Workflow:</b> ' + esc(wfName) + '<br><b>Nodo:</b> ' + esc(node) + '<br><b>Error:</b> ' + esc(msg) + '</p>' +
  '<pre style="background:#f5f5f5;padding:8px;font-size:12px;white-space:pre-wrap">' + esc(stack) + '</pre></div>';
return [{ json: { payload: { from: 'CarsWise n8n <onboarding@resend.dev>', to: 'akangarooh23@gmail.com', subject: subject, html: html } } }];
